import React, { useState, useEffect } from 'react';
import Layout from '../components/Layout';
import { ArrowLeft, CreditCard, Lock, CheckCircle } from 'lucide-react';
import { Link } from 'react-router-dom';

interface OrderItem {
  id: string;
  title: string;
  difficulty: string;
  points: number;
  price: number;
  image: string;
}

const PaymentPage: React.FC = () => {
  const [paymentMethod, setPaymentMethod] = useState('card');
  const [cardNumber, setCardNumber] = useState('');
  const [expiry, setExpiry] = useState('');
  const [cvv, setCvv] = useState('');
  const [name, setName] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const [isSuccess, setIsSuccess] = useState(false);
  const [orderItems, setOrderItems] = useState<OrderItem[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  // Fetch order items from backend
  useEffect(() => {
    const fetchOrderItems = async () => {
      try {
        setLoading(true);
        
        // In a real implementation, we would fetch data from the backend
        // For now, we'll use mock data but simulate an API call
        await new Promise(resolve => setTimeout(resolve, 1000));
        
        // Mock order items (will be replaced with real data from backend)
        const mockOrderItems: OrderItem[] = [
          {
            id: "1",
            title: "Complex Criminal Trial Simulation",
            difficulty: "Expert",
            points: 2990,
            price: 299,
            image: ""
          },
          {
            id: "2",
            title: "Corporate Merger Negotiation",
            difficulty: "Advanced",
            points: 1990,
            price: 199,
            image: ""
          },
          {
            id: "3",
            title: "Family Mediation Mastery",
            difficulty: "Intermediate",
            points: 1490,
            price: 149,
            image: ""
          }
        ];
        
        setOrderItems(mockOrderItems);
        setLoading(false);
      } catch (err) {
        setError('Error fetching order items: ' + (err as Error).message);
        console.error('Error fetching order items:', err);
        setLoading(false);
      }
    };

    fetchOrderItems();
  }, []);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setIsProcessing(true);
    
    // Simulate payment processing
    setTimeout(() => {
      setIsProcessing(false);
      setIsSuccess(true);
    }, 2000);
  };

  const subtotal = orderItems.reduce((sum, item) => sum + item.price, 0);
  const discount = 65;
  const tax = Math.round(subtotal * 0.18); // 18% tax
  const total = subtotal - discount + tax;
  const totalPoints = orderItems.reduce((sum, item) => sum + item.points, 0);

  if (loading) {
    return (
      <Layout>
        <div className="container mx-auto px-4 py-12">
          <div className="text-center">
            <div className="inline-block animate-spin rounded-full h-12 w-12 border-t-2 border-b-2 border-indigo-600 mb-4"></div>
            <p className="text-gray-600">Loading payment details...</p>
          </div>
        </div>
      </Layout>
    );
  }

  if (error) {
    return (
      <Layout>
        <div className="container mx-auto px-4 py-12">
          <div className="text-center py-12">
            <div className="bg-red-100 rounded-full w-16 h-16 flex items-center justify-center mx-auto mb-4">
              <svg className="w-8 h-8 text-red-600" fill="none" stroke="currentColor" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z"></path>
              </svg>
            </div>
            <h3 className="text-xl font-bold text-gray-900 mb-2">Error Loading Payment Details</h3>
            <p className="text-gray-600 mb-4">{error}</p>
            <button 
              className="bg-indigo-600 text-white px-6 py-3 rounded-lg hover:bg-indigo-700 transition duration-300 font-medium"
              onClick={() => window.location.reload()}
            >
              Try Again
            </button>
          </div>
        </div>
      </Layout>
    );
  }

  if (isSuccess) {
    return (
      <Layout>
        <div className="container mx-auto px-4 py-12">
          <div className="max-w-2xl mx-auto bg-white rounded-xl shadow-lg p-8 text-center">
            <div className="w-20 h-20 bg-green-100 rounded-full flex items-center justify-center mx-auto mb-6">
              <CheckCircle className="w-12 h-12 text-green-500" />
            </div>
            <h2 className="text-3xl font-bold text-gray-900 mb-4">Payment Successful!</h2>
            <p className="text-gray-600 mb-6">
              Your payment has been processed successfully. You will receive a confirmation email shortly.
            </p>
            <div className="bg-gray-50 rounded-lg p-6 mb-6">
              <h3 className="font-bold text-gray-900 mb-2">Order Summary</h3>
              {orderItems.map(item => (
                <div key={item.id} className="flex justify-between py-2">
                  <span>{item.title}</span>
                  <span>{item.points} points</span>
                </div>
              ))}
              <div className="border-t border-gray-200 mt-4 pt-4 flex justify-between font-bold">
                <span>Total</span>
                <span>{totalPoints} points</span>
              </div>
            </div>
            <Link to="/dashboard">
              <button className="bg-indigo-600 text-white px-6 py-3 rounded-lg hover:bg-indigo-700 transition duration-300 font-medium">
                Continue to Dashboard
              </button>
            </Link>
          </div>
        </div>
      </Layout>
    );
  }

  return (
    <Layout>
      <div className="container mx-auto px-4 py-12">
        <div className="mb-6">
          <Link to="/marketplace" className="flex items-center text-indigo-600 hover:text-indigo-800 transition duration-300">
            <ArrowLeft className="w-5 h-5 mr-2" />
            Back to Marketplace
          </Link>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
          {/* Payment Form */}
          <div className="bg-white rounded-xl shadow-lg p-8">
            <h2 className="text-2xl font-bold text-gray-900 mb-6">Payment Details</h2>
            
            <div className="mb-8">
              <h3 className="font-bold text-gray-900 mb-4">Payment Method</h3>
              <div className="flex space-x-4">
                <button
                  className={`flex-1 py-3 px-4 rounded-lg border ${
                    paymentMethod === 'card' 
                      ? 'border-indigo-500 bg-indigo-50' 
                      : 'border-gray-300 hover:border-gray-400'
                  }`}
                  onClick={() => setPaymentMethod('card')}
                >
                  <CreditCard className="w-6 h-6 mx-auto mb-2 text-gray-700" />
                  <span className="text-sm font-medium">Credit Card</span>
                </button>
                <button
                  className={`flex-1 py-3 px-4 rounded-lg border ${
                    paymentMethod === 'upi' 
                      ? 'border-indigo-500 bg-indigo-50' 
                      : 'border-gray-300 hover:border-gray-400'
                  }`}
                  onClick={() => setPaymentMethod('upi')}
                >
                  <div className="bg-gray-200 border-2 border-dashed rounded-xl w-6 h-6 mx-auto mb-2" />
                  <span className="text-sm font-medium">UPI</span>
                </button>
                <button
                  className={`flex-1 py-3 px-4 rounded-lg border ${
                    paymentMethod === 'paypal' 
                      ? 'border-indigo-500 bg-indigo-50' 
                      : 'border-gray-300 hover:border-gray-400'
                  }`}
                  onClick={() => setPaymentMethod('paypal')}
                >
                  <div className="bg-gray-200 border-2 border-dashed rounded-xl w-6 h-6 mx-auto mb-2" />
                  <span className="text-sm font-medium">PayPal</span>
                </button>
              </div>
            </div>

            <form onSubmit={handleSubmit}>
              <div className="space-y-6">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">Card Number</label>
                  <input
                    type="text"
                    value={cardNumber}
                    onChange={(e) => setCardNumber(e.target.value)}
                    placeholder="1234 5678 9012 3456"
                    className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent"
                    required
                  />
                </div>
                
                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <label className="block text-sm font-medium text-gray-700 mb-2">Expiry Date</label>
                    <input
                      type="text"
                      value={expiry}
                      onChange={(e) => setExpiry(e.target.value)}
                      placeholder="MM/YY"
                      className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent"
                      required
                    />
                  </div>
                  <div>
                    <label className="block text-sm font-medium text-gray-700 mb-2">CVV</label>
                    <input
                      type="text"
                      value={cvv}
                      onChange={(e) => setCvv(e.target.value)}
                      placeholder="123"
                      className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent"
                      required
                    />
                  </div>
                </div>
                
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">Cardholder Name</label>
                  <input
                    type="text"
                    value={name}
                    onChange={(e) => setName(e.target.value)}
                    placeholder="John Doe"
                    className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent"
                    required
                  />
                </div>
                
                <div className="flex items-center p-4 bg-blue-50 rounded-lg">
                  <Lock className="w-5 h-5 text-blue-500 mr-2" />
                  <p className="text-sm text-blue-700">
                    Your payment details are securely encrypted and processed.
                  </p>
                </div>
                
                <button
                  type="submit"
                  disabled={isProcessing}
                  className="w-full bg-gradient-to-r from-indigo-600 to-purple-600 text-white py-3 rounded-lg hover:from-indigo-700 hover:to-purple-700 transition duration-300 font-medium flex items-center justify-center disabled:opacity-50"
                >
                  {isProcessing ? (
                    <>
                      <svg className="animate-spin -ml-1 mr-3 h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                        <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                        <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                      </svg>
                      Processing...
                    </>
                  ) : (
                    `Complete Payment (₹${total})`
                  )}
                </button>
              </div>
            </form>
          </div>
          
          {/* Order Summary */}
          <div className="bg-white rounded-xl shadow-lg p-8">
            <h2 className="text-2xl font-bold text-gray-900 mb-6">Order Summary</h2>
            
            <div className="space-y-6">
              <div className="border-b border-gray-200 pb-6">
                <h3 className="font-bold text-gray-900 mb-4">Items</h3>
                <div className="space-y-4">
                  {orderItems.map(item => (
                    <div key={item.id} className="flex items-center">
                      <div className="bg-gray-200 border-2 border-dashed rounded-xl w-16 h-16" />
                      <div className="ml-4 flex-1">
                        <h4 className="font-medium text-gray-900">{item.title}</h4>
                        <p className="text-gray-600 text-sm">{item.difficulty} • {item.points} points</p>
                      </div>
                      <span className="font-medium">₹{item.price}</span>
                    </div>
                  ))}
                </div>
              </div>
              
              <div className="border-b border-gray-200 pb-6">
                <h3 className="font-bold text-gray-900 mb-4">Price Details</h3>
                <div className="space-y-2">
                  <div className="flex justify-between">
                    <span className="text-gray-600">Subtotal</span>
                    <span>₹{subtotal}</span>
                  </div>
                  <div className="flex justify-between">
                    <span className="text-gray-600">Discount</span>
                    <span className="text-green-600">-₹{discount}</span>
                  </div>
                  <div className="flex justify-between">
                    <span className="text-gray-600">Tax</span>
                    <span>₹{tax}</span>
                  </div>
                  <div className="flex justify-between font-bold text-lg mt-4">
                    <span>Total</span>
                    <span>₹{total}</span>
                  </div>
                </div>
              </div>
              
              <div className="bg-gradient-to-r from-indigo-50 to-purple-50 rounded-lg p-4">
                <div className="flex items-center">
                  <div className="w-12 h-12 bg-indigo-100 rounded-full flex items-center justify-center mr-4">
                    <CreditCard className="w-6 h-6 text-indigo-600" />
                  </div>
                  <div>
                    <h4 className="font-bold text-gray-900">Points Bonus</h4>
                    <p className="text-gray-600 text-sm">You'll receive {totalPoints} points after payment</p>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </Layout>
  );
};

export default PaymentPage;
